create extension if not exists pgcrypto;
drop view if exists leaderboard; drop table if exists predictions cascade; drop table if exists participants cascade; drop table if exists fixtures cascade;
create table participants (id uuid primary key default gen_random_uuid(), full_name text not null unique, created_at timestamptz not null default now());
create table fixtures (id bigint generated always as identity primary key, stage_name text not null default 'دور الـ16', display_order int not null default 0, home_team text not null, away_team text not null, kickoff_at timestamptz not null, first_leg_home_goals int not null default 0, first_leg_away_goals int not null default 0, actual_home_goals int null, actual_away_goals int null, lock_minutes_before int not null default 10, went_extra_time boolean not null default false, went_penalties boolean not null default false, penalties_winner text null, created_at timestamptz not null default now());
create table predictions (id bigint generated always as identity primary key, participant_id uuid not null references participants(id) on delete cascade, fixture_id bigint not null references fixtures(id) on delete cascade, pred_home_goals int not null check (pred_home_goals >= 0), pred_away_goals int not null check (pred_away_goals >= 0), pred_extra_time boolean not null default false, pred_penalties boolean not null default false, pred_penalties_winner text null, created_at timestamptz not null default now(), updated_at timestamptz not null default now(), unique (participant_id, fixture_id));
create or replace function set_updated_at() returns trigger as $$ begin new.updated_at = now(); return new; end; $$ language plpgsql;
drop trigger if exists trg_predictions_updated_at on predictions;
create trigger trg_predictions_updated_at before update on predictions for each row execute function set_updated_at();
create or replace function calc_prediction_points(pred_home int,pred_away int,real_home int,real_away int,pred_extra boolean,real_extra boolean,pred_pens boolean,real_pens boolean,pred_pens_winner text,real_pens_winner text) returns int language plpgsql immutable as $$ declare points int := 0; pred_outcome text; real_outcome text; pred_diff int; real_diff int; distance int; begin if pred_home is null or pred_away is null or real_home is null or real_away is null then return 0; end if; if pred_home = real_home and pred_away = real_away then points := 10; else pred_outcome := case when pred_home > pred_away then 'H' when pred_home < pred_away then 'A' else 'D' end; real_outcome := case when real_home > real_away then 'H' when real_home < real_away then 'A' else 'D' end; pred_diff := pred_home - pred_away; real_diff := real_home - real_away; if pred_outcome = real_outcome and pred_diff = real_diff then points := 7; elsif pred_outcome = real_outcome then points := 5; end if; if pred_home = real_home or pred_away = real_away then points := points + 3; end if; distance := abs(pred_home - real_home) + abs(pred_away - real_away); if distance = 1 then points := points + 2; elsif distance = 2 then points := points + 1; end if; end if; if pred_extra = real_extra then points := points + 2; end if; if pred_pens = real_pens then points := points + 2; end if; if real_pens = true and pred_pens_winner is not null and pred_pens_winner = real_pens_winner then points := points + 3; end if; return points; end; $$;
create or replace view leaderboard as with scored as (select p.id as participant_id,p.full_name,pr.fixture_id,calc_prediction_points(pr.pred_home_goals,pr.pred_away_goals,f.actual_home_goals,f.actual_away_goals,pr.pred_extra_time,f.went_extra_time,pr.pred_penalties,f.went_penalties,pr.pred_penalties_winner,f.penalties_winner) as points,case when f.actual_home_goals is not null and f.actual_away_goals is not null and pr.pred_home_goals = f.actual_home_goals and pr.pred_away_goals = f.actual_away_goals then 1 else 0 end as exact_hit,(case when pr.pred_extra_time = f.went_extra_time then 1 else 0 end + case when pr.pred_penalties = f.went_penalties then 1 else 0 end + case when f.went_penalties = true and pr.pred_penalties_winner = f.penalties_winner then 1 else 0 end) as special_hit,case when f.actual_home_goals is not null and f.actual_away_goals is not null then abs(pr.pred_home_goals - f.actual_home_goals) + abs(pr.pred_away_goals - f.actual_away_goals) else 999 end as distance from participants p left join predictions pr on pr.participant_id = p.id left join fixtures f on f.id = pr.fixture_id) select participant_id,full_name,coalesce(sum(points),0) as total_points,count(fixture_id) as predictions_count,coalesce(sum(exact_hit),0) as exact_scores_count,coalesce(sum(special_hit),0) as special_hits_count,coalesce(sum(distance),0) as total_distance,row_number() over(order by coalesce(sum(points),0) desc, coalesce(sum(exact_hit),0) desc, coalesce(sum(special_hit),0) desc, coalesce(sum(distance),0) asc, full_name asc) as rank_order from scored group by participant_id, full_name order by rank_order;
alter table participants enable row level security; alter table fixtures enable row level security; alter table predictions enable row level security;
drop policy if exists participants_select on participants; drop policy if exists participants_insert on participants; drop policy if exists fixtures_select on fixtures; drop policy if exists fixtures_insert on fixtures; drop policy if exists fixtures_update on fixtures; drop policy if exists predictions_select on predictions; drop policy if exists predictions_insert on predictions; drop policy if exists predictions_update on predictions;
create policy participants_select on participants for select using (true); create policy participants_insert on participants for insert with check (true); create policy fixtures_select on fixtures for select using (true); create policy fixtures_insert on fixtures for insert with check (true); create policy fixtures_update on fixtures for update using (true) with check (true); create policy predictions_select on predictions for select using (true); create policy predictions_insert on predictions for insert with check (true); create policy predictions_update on predictions for update using (true) with check (true);
grant usage on schema public to anon, authenticated; grant select, insert, update on participants to anon, authenticated; grant select, insert, update on fixtures to anon, authenticated; grant select, insert, update on predictions to anon, authenticated; grant select on leaderboard to anon, authenticated;
